-- IronRAG 0.5.0 clean baseline schema.
-- Baseline reset: replaces migrations 0001-0017 and draft 0018.
-- Relational core is mechanically derived from .omc/research/arango-audit/current-schema-dump.sql.
-- SQLx bookkeeping (_sqlx_migrations) and pg_dump session/ownership/ACL noise are intentionally excluded.
-- Knowledge-plane DDL is folded from the dry-run-verified 0018 knowledge-plane draft.

-- Extensions
create extension IF NOT EXISTS btree_gin WITH SCHEMA public;

create extension IF NOT EXISTS dblink WITH SCHEMA public;

create extension IF NOT EXISTS pg_trgm WITH SCHEMA public;

create extension IF NOT EXISTS pgcrypto WITH SCHEMA public;

create extension if not exists vector;

create extension if not exists unaccent;

-- Functions
create or replace function ironrag_unaccent(input text)
returns text
language plpgsql
immutable
parallel safe
as $$
begin
    return public.unaccent('public.unaccent'::regdictionary, input);
end;
$$;

comment on function ironrag_unaccent(text) is
    'Immutable wrapper used by generated script-agnostic FTS columns: to_tsvector(''simple'', ironrag_unaccent(...)).';

create or replace function ironrag_array_join(input text[])
returns text
language plpgsql
immutable
parallel safe
as $$
begin
    return array_to_string(input, ' ');
end;
$$;

create or replace function public.uuidv7() RETURNS uuid
    LANGUAGE plpgsql
    AS $$
declare
    unix_ts_ms bigint;
    uuid_bytes bytea;
begin
    unix_ts_ms = (extract(epoch from clock_timestamp()) * 1000)::bigint;
    uuid_bytes = set_byte(
        set_byte(
            overlay(
                uuid_send(gen_random_uuid())
                placing substring(int8send(unix_ts_ms) from 3)
                from 1 for 6
            ),
            6, (get_byte(uuid_send(gen_random_uuid()), 6) & 15) | 112
        ),
        8, (get_byte(uuid_send(gen_random_uuid()), 8) & 63) | 128
    );
    return encode(uuid_bytes, 'hex')::uuid;
end
$$;

