-- Baseline cleanup notes:
-- Dropped: public._sqlx_migrations only. SQLx owns this table outside application migrations.
-- Dropped: static legacy/single-dimension vector tables. The current relational core dump had none;
-- the 0.5.0 baseline keeps only knowledge_vector_relation_manifest because W0 creates typed
-- per-dimension vector relations and promoted library partitions at runtime.
-- No other relational-core tables were clearly dead from the pg_dump alone.
-- TODO(WB review): confirm whether entity_dedup_verification_cache and extract_* helper tables
-- remain needed after the PostgreSQL knowledge-plane implementation lands; kept conservatively
-- because they are part of current graph extraction/ingest runtime state, not standalone Arango bridges.
-- TODO(WB review): confirm runtime_provider_profile.summary_embedding remains useful after
-- per-dimension pgvector entity/chunk vector relations are bootstrapped; kept as runtime metadata.

-- Relational core tables
create table if not exists public.ai_binding_assignment (
    id uuid DEFAULT uuidv7() NOT NULL,
    workspace_id uuid,
    library_id uuid,
    binding_purpose public.ai_binding_purpose NOT NULL,
    provider_credential_id uuid NOT NULL,
    model_preset_id uuid NOT NULL,
    binding_state public.ai_binding_state DEFAULT 'active'::public.ai_binding_state NOT NULL,
    scope_kind public.ai_scope_kind NOT NULL,
    updated_by_principal_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT ai_binding_assignment_scope_check CHECK ((((scope_kind = 'instance'::public.ai_scope_kind) AND (workspace_id IS NULL) AND (library_id IS NULL)) OR ((scope_kind = 'workspace'::public.ai_scope_kind) AND (workspace_id IS NOT NULL) AND (library_id IS NULL)) OR ((scope_kind = 'library'::public.ai_scope_kind) AND (workspace_id IS NOT NULL) AND (library_id IS NOT NULL))))
);

create table if not exists public.ai_binding_validation (
    id uuid DEFAULT uuidv7() NOT NULL,
    binding_id uuid NOT NULL,
    validation_state public.ai_validation_state NOT NULL,
    checked_at timestamp with time zone DEFAULT now() NOT NULL,
    failure_code text,
    message text
);

create table if not exists public.ai_model_catalog (
    id uuid NOT NULL,
    provider_catalog_id uuid NOT NULL,
    model_name text NOT NULL,
    capability_kind public.ai_model_capability_kind NOT NULL,
    modality_kind public.ai_model_modality_kind NOT NULL,
    context_window integer,
    max_output_tokens integer,
    lifecycle_state public.ai_model_lifecycle_state DEFAULT 'active'::public.ai_model_lifecycle_state NOT NULL,
    metadata_json jsonb NOT NULL,
    CONSTRAINT ai_model_catalog_default_roles_check CHECK (
CASE
    WHEN (jsonb_typeof((metadata_json -> 'defaultRoles'::text)) = 'array'::text) THEN (jsonb_array_length((metadata_json -> 'defaultRoles'::text)) > 0)
    ELSE false
END)
);

create table if not exists public.ai_model_preset (
    id uuid DEFAULT uuidv7() NOT NULL,
    workspace_id uuid,
    model_catalog_id uuid NOT NULL,
    preset_name text NOT NULL,
    system_prompt text,
    temperature double precision,
    top_p double precision,
    max_output_tokens_override integer,
    extra_parameters_json jsonb DEFAULT '{}'::jsonb NOT NULL,
    scope_kind public.ai_scope_kind NOT NULL,
    library_id uuid,
    created_by_principal_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
