    created_by_principal_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    web_ingest_policy jsonb DEFAULT '{"crawlFilter": {"allowPatterns": [], "blockPatterns": [{"kind": "path_prefix", "value": "/aboutconfluencepage.action"}, {"kind": "path_prefix", "value": "/collector/pages.action"}, {"kind": "path_prefix", "value": "/dashboard/configurerssfeed.action"}, {"kind": "path_prefix", "value": "/exportword"}, {"kind": "path_prefix", "value": "/forgotuserpassword.action"}, {"kind": "path_prefix", "value": "/label/"}, {"kind": "path_prefix", "value": "/labels/"}, {"kind": "path_prefix", "value": "/login.action"}, {"kind": "path_prefix", "value": "/pages/diffpages.action"}, {"kind": "path_prefix", "value": "/pages/diffpagesbyversion.action"}, {"kind": "path_prefix", "value": "/pages/listundefinedpages.action"}, {"kind": "path_prefix", "value": "/pages/reorderpages.action"}, {"kind": "path_prefix", "value": "/pages/viewinfo.action"}, {"kind": "path_prefix", "value": "/pages/viewpageattachments.action"}, {"kind": "path_prefix", "value": "/pages/viewpreviousversions.action"}, {"kind": "path_prefix", "value": "/pages/worddav/"}, {"kind": "path_prefix", "value": "/plugins/recently-updated/"}, {"kind": "path_prefix", "value": "/plugins/viewsource/viewpagesrc.action"}, {"kind": "path_prefix", "value": "/dashboard.action"}, {"kind": "path_prefix", "value": "/spacedirectory/view.action"}, {"kind": "path_prefix", "value": "/spaces/flyingpdf/pdfpageexport.action"}, {"kind": "path_prefix", "value": "/spaces/listattachmentsforspace.action"}, {"kind": "path_prefix", "value": "/spaces/listrssfeeds.action"}, {"kind": "path_prefix", "value": "/spaces/viewspacesummary.action"}, {"kind": "glob", "value": "*/display/~*"}, {"kind": "glob", "value": "*fileExtension=*"}, {"kind": "glob", "value": "*labels=*"}, {"kind": "glob", "value": "*metadataLink=*"}, {"kind": "glob", "value": "*navigatingVersions=*"}, {"kind": "glob", "value": "*openId=*"}, {"kind": "glob", "value": "*originalVersion=*"}, {"kind": "glob", "value": "*os_destination=*"}, {"kind": "glob", "value": "*permissionViolation=*"}, {"kind": "glob", "value": "*permissionviolation=*"}, {"kind": "glob", "value": "*revisedVersion=*"}, {"kind": "glob", "value": "*selectedPageVersions=*"}, {"kind": "glob", "value": "*sortBy=*"}]}, "materializationFilter": {"allowPatterns": [], "blockPatterns": []}}'::jsonb NOT NULL,
    chunking_template text DEFAULT 'naive'::text NOT NULL,
    recognition_policy jsonb DEFAULT '{"rasterImageEngine": "vision"}'::jsonb NOT NULL,
    include_document_hint_in_mcp_answers boolean DEFAULT true NOT NULL,
    CONSTRAINT catalog_library_recognition_policy_object_check CHECK ((jsonb_typeof(recognition_policy) = 'object'::text)),
    CONSTRAINT catalog_library_recognition_policy_raster_engine_check CHECK (((recognition_policy ? 'rasterImageEngine'::text) AND ((recognition_policy ->> 'rasterImageEngine'::text) = ANY (ARRAY['docling'::text, 'vision'::text])) AND ((recognition_policy - 'rasterImageEngine'::text) = '{}'::jsonb))),
    CONSTRAINT catalog_library_slug_check CHECK ((slug ~ '^[a-z0-9]+(?:[-_][a-z0-9]+)*$'::text)),
    CONSTRAINT catalog_library_web_ingest_policy_object_check CHECK ((jsonb_typeof(web_ingest_policy) = 'object'::text))
);

