    created_by_principal_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    deleted_at timestamp with time zone,
    -- Structural source parentage: a document admitted as a dependent of
    -- another source document (e.g. a page attachment) records the declared
    -- parent key and, once resolved, the canonical parent document id.
    -- document_role is decided once at admission/backfill from structural
    -- inputs (declared parentage + revision media class); retrieval reads
    -- only the role.
    parent_document_id uuid,
    parent_external_key text,
    document_role text DEFAULT 'primary' NOT NULL,
    CONSTRAINT content_document_role_ck CHECK (document_role IN ('primary', 'attachment', 'attached_context')),
    CONSTRAINT content_document_no_self_parent_ck CHECK (parent_document_id IS NULL OR parent_document_id <> id)
);

