-- PostgreSQL knowledge-plane tables
create table if not exists knowledge_document (
    document_id uuid primary key,
    workspace_id uuid not null,
    library_id uuid not null,
    external_key text not null,
    file_name text,
    title text,
    document_state text not null,
    active_revision_id uuid,
    readable_revision_id uuid,
    latest_revision_no bigint,
    created_at timestamptz not null,
    updated_at timestamptz not null,
    deleted_at timestamptz,
    -- Mirror of content_document structural parentage (see content_document).
    parent_document_id uuid,
    document_role text default 'primary' not null
);

create index if not exists idx_knowledge_document_library_parent
    on knowledge_document (library_id, parent_document_id)
    where parent_document_id is not null;

comment on table knowledge_document is
    'Replaces Arango document collection knowledge_document; active/readable revision pointers replace document_revision edge lookups.';

create table if not exists knowledge_revision (
    revision_id uuid primary key,
    workspace_id uuid not null,
    library_id uuid not null,
    document_id uuid not null,
    revision_number bigint not null,
    revision_state text not null,
    revision_kind text not null,
    storage_ref text,
    source_uri text,
    document_hint text,
    mime_type text not null,
    checksum text not null,
    title text,
    byte_size bigint not null,
    normalized_text text,
    text_checksum text,
    image_checksum text,
    text_state text not null,
    vector_state text not null,
    graph_state text not null,
    text_readable_at timestamptz,
    vector_ready_at timestamptz,
    graph_ready_at timestamptz,
    superseded_by_revision_id uuid,
    created_at timestamptz not null
);

comment on table knowledge_revision is
    'Replaces Arango collection knowledge_revision and collapses knowledge_document_revision_edge into document_id.';

create table if not exists knowledge_structured_revision (
    revision_id uuid primary key,
    workspace_id uuid not null,
    library_id uuid not null,
    document_id uuid not null,
    preparation_state text not null,
    normalization_profile text not null,
    source_format text not null,
    language_code text,
    block_count bigint not null,
    chunk_count bigint not null,
    typed_fact_count bigint not null,
    outline_json jsonb not null,
    prepared_at timestamptz not null,
    updated_at timestamptz not null
);

comment on table knowledge_structured_revision is
    'Replaces Arango collection knowledge_structured_revision; revision/document relationship is a direct FK.';

create table if not exists knowledge_structured_block (
    block_id uuid primary key,
    workspace_id uuid not null,
    library_id uuid not null,
    document_id uuid not null,
    revision_id uuid not null,
    ordinal integer not null,
    block_kind text not null,
    text text not null,
    normalized_text text not null,
    heading_trail text[] not null default '{}',
    section_path text[] not null default '{}',
    page_number integer,
    span_start integer,
    span_end integer,
    parent_block_id uuid,
    table_coordinates_json jsonb,
    code_language text,
    occurred_at timestamptz,
    occurred_until timestamptz,
    created_at timestamptz not null,
    updated_at timestamptz not null,
    search_tsv tsvector generated always as (
        to_tsvector(
            'simple',
            ironrag_unaccent(
                coalesce(text, '') || ' ' ||
                coalesce(normalized_text, '') || ' ' ||
                coalesce(ironrag_array_join(heading_trail), '') || ' ' ||
                coalesce(ironrag_array_join(section_path), '')
            )
        )
    ) stored
);

comment on table knowledge_structured_block is
    'Replaces Arango collection knowledge_structured_block and collapses knowledge_revision_block_edge into revision_id. occurred_at/occurred_until replace REGEX_EXTRACT temporal parsing from normalized_text.';

create table if not exists knowledge_chunk (
    chunk_id uuid primary key,
    workspace_id uuid not null,
    library_id uuid not null,
    document_id uuid not null,
    revision_id uuid not null,
    primary_block_id uuid,
    chunk_index integer not null,
    chunk_kind text,
    content_text text not null,
    normalized_text text not null,
    span_start integer,
    span_end integer,
    token_count integer,
    support_block_ids uuid[] not null default '{}',
    section_path text[] not null default '{}',
    heading_trail text[] not null default '{}',
    literal_digest text,
    chunk_state text not null,
    text_generation bigint,
    vector_generation bigint,
    quality_score real,
    window_text text,
    raptor_level integer,
    occurred_at timestamptz,
    occurred_until timestamptz,
    search_tsv tsvector generated always as (
        to_tsvector(
            'simple',
            ironrag_unaccent(
                coalesce(content_text, '') || ' ' ||
                coalesce(normalized_text, '') || ' ' ||
                coalesce(window_text, '') || ' ' ||
                coalesce(ironrag_array_join(section_path), '') || ' ' ||
                coalesce(ironrag_array_join(heading_trail), '')
            )
        )
    ) stored
);

comment on table knowledge_chunk is
    'Replaces Arango collection knowledge_chunk and collapses knowledge_revision_chunk_edge into revision_id. primary_block_id/support_block_ids replace knowledge_block_chunk_edge without a separate edge table.';

create table if not exists knowledge_technical_fact (
    fact_id uuid primary key,
    workspace_id uuid not null,
    library_id uuid not null,
    document_id uuid not null,
    revision_id uuid not null,
    fact_kind text not null,
    canonical_value_text text not null,
    canonical_value_exact text not null,
    canonical_value_json jsonb not null,
    display_value text not null,
    qualifiers_json jsonb not null,
    support_block_ids uuid[] not null default '{}',
    support_chunk_ids uuid[] not null default '{}',
    confidence double precision,
    extraction_kind text not null,
    conflict_group_id text,
    created_at timestamptz not null,
    updated_at timestamptz not null,
    search_tsv tsvector generated always as (
        to_tsvector(
            'simple',
            ironrag_unaccent(
                coalesce(canonical_value_text, '') || ' ' ||
                coalesce(display_value, '')
            )
        )
    ) stored
);

comment on table knowledge_technical_fact is
    'Replaces Arango collection knowledge_technical_fact; fact_evidence is represented by knowledge_evidence.fact_id when evidence is fact-backed.';

create table if not exists knowledge_entity (
    entity_id uuid primary key,
    workspace_id uuid not null,
    library_id uuid not null,
    canonical_label text not null,
    aliases text[] not null default '{}',
    entity_type text not null,
    entity_sub_type text,
    summary text,
    confidence double precision,
    support_count bigint not null,
    freshness_generation bigint not null,
    entity_state text not null,
    created_at timestamptz not null,
    updated_at timestamptz not null,
    search_tsv tsvector generated always as (
        to_tsvector(
            'simple',
            ironrag_unaccent(
                coalesce(canonical_label, '') || ' ' ||
                coalesce(summary, '') || ' ' ||
                coalesce(ironrag_array_join(aliases), '')
            )
        )
    ) stored
);

comment on table knowledge_entity is
    'Replaces Arango collection knowledge_entity for the materialized knowledge-plane entity rows. Canonical query graph remains runtime_graph_node.';

create table if not exists knowledge_entity_candidate (
    candidate_id uuid primary key,
    workspace_id uuid not null,
    library_id uuid not null,
    revision_id uuid not null,
    chunk_id uuid,
    candidate_label text not null,
    candidate_type text not null,
    candidate_sub_type text,
    normalization_key text not null,
    confidence double precision,
    extraction_method text not null,
    candidate_state text not null,
    created_at timestamptz not null,
    updated_at timestamptz not null
);

comment on table knowledge_entity_candidate is
    'Replaces Arango collection knowledge_entity_candidate; candidate staging rows are revision/chunk scoped.';

create table if not exists knowledge_relation (
    relation_id uuid primary key,
    workspace_id uuid not null,
    library_id uuid not null,
    subject_entity_id uuid,
    object_entity_id uuid,
    predicate text not null,
    normalized_assertion text not null,
    summary text,
    confidence double precision,
    support_count bigint not null,
    contradiction_state text not null,
    freshness_generation bigint not null,
    relation_state text not null,
    created_at timestamptz not null,
    updated_at timestamptz not null,
    search_tsv tsvector generated always as (
        to_tsvector(
            'simple',
            ironrag_unaccent(
                coalesce(predicate, '') || ' ' ||
                coalesce(normalized_assertion, '') || ' ' ||
                coalesce(summary, '')
            )
        )
    ) stored
);

comment on table knowledge_relation is
    'Replaces Arango collection knowledge_relation and collapses relation_subject/object edges into subject_entity_id/object_entity_id. Canonical query graph remains runtime_graph_edge.';

create table if not exists knowledge_relation_candidate (
    candidate_id uuid primary key,
    workspace_id uuid not null,
    library_id uuid not null,
    revision_id uuid not null,
    chunk_id uuid,
    subject_label text not null default '',
    subject_candidate_key text not null,
    predicate text not null,
    object_label text not null default '',
    object_candidate_key text not null,
    normalized_assertion text not null,
    confidence double precision,
    extraction_method text not null,
    candidate_state text not null,
    created_at timestamptz not null,
    updated_at timestamptz not null
);

comment on table knowledge_relation_candidate is
    'Replaces Arango collection knowledge_relation_candidate; candidate staging rows are revision/chunk scoped.';

create table if not exists knowledge_evidence (
    evidence_id uuid primary key,
    workspace_id uuid not null,
    library_id uuid not null,
    document_id uuid not null,
    revision_id uuid not null,
    chunk_id uuid,
    block_id uuid,
    fact_id uuid,
    span_start integer,
    span_end integer,
    quote_text text not null default '',
    literal_spans_json jsonb not null default '{}'::jsonb,
    summary text,
    evidence_kind text not null default '',
    extraction_method text not null,
    confidence double precision,
    evidence_state text not null,
    freshness_generation bigint not null,
    created_at timestamptz not null,
    updated_at timestamptz not null,
    search_tsv tsvector generated always as (
        to_tsvector(
            'simple',
            ironrag_unaccent(
                coalesce(quote_text, '') || ' ' ||
                coalesce(summary, '')
            )
        )
    ) stored
);

comment on table knowledge_evidence is
    'Replaces Arango collection knowledge_evidence and collapses evidence_source_edge/fact_evidence_edge into document_id/revision_id/chunk_id/block_id/fact_id. TODO W1 review: bootstrap declared evidence_source_edge as EVIDENCE->CHUNK but writes used EVIDENCE->REVISION; this table keeps both revision_id and optional chunk_id.';

create table if not exists knowledge_context_bundle (
    bundle_id uuid primary key,
    workspace_id uuid not null,
    library_id uuid not null,
    query_execution_id uuid,
    bundle_state text not null,
    bundle_strategy text not null,
    requested_mode text not null,
    resolved_mode text not null,
    selected_fact_ids uuid[] not null default '{}',
    verification_state text not null,
    verification_warnings jsonb not null default '[]'::jsonb,
    freshness_snapshot jsonb not null default '{}'::jsonb,
    candidate_summary jsonb not null default '{}'::jsonb,
    assembly_diagnostics jsonb not null default '{}'::jsonb,
    created_at timestamptz not null,
    updated_at timestamptz not null
);

comment on table knowledge_context_bundle is
    'Replaces Arango collection knowledge_context_bundle; bundle edges become four ranked child tables with ON DELETE CASCADE.';

create table if not exists knowledge_retrieval_trace (
    trace_id uuid primary key,
    workspace_id uuid not null,
    library_id uuid not null,
    query_execution_id uuid,
    bundle_id uuid not null,
    trace_state text not null,
    retrieval_strategy text not null,
    candidate_counts jsonb not null default '{}'::jsonb,
    dropped_reasons jsonb not null default '{}'::jsonb,
    timing_breakdown jsonb not null default '{}'::jsonb,
    diagnostics_json jsonb not null default '{}'::jsonb,
    created_at timestamptz not null,
    updated_at timestamptz not null
);

comment on table knowledge_retrieval_trace is
    'Replaces Arango collection knowledge_retrieval_trace; stores retrieval diagnostics and bundle snapshots.';

create table if not exists knowledge_bundle_chunk (
    bundle_id uuid not null,
    chunk_id uuid not null,
    library_id uuid not null,
    rank integer not null,
    score double precision not null,
    inclusion_reason text,
    created_at timestamptz not null,
    primary key (bundle_id, chunk_id)
);

comment on table knowledge_bundle_chunk is
    'Replaces Arango edge collection knowledge_bundle_chunk_edge; a context-bundle child table, not a graph traversal edge.';

create table if not exists knowledge_bundle_entity (
    bundle_id uuid not null,
    entity_id uuid not null,
    library_id uuid not null,
    rank integer not null,
    score double precision not null,
    inclusion_reason text,
    created_at timestamptz not null,
    primary key (bundle_id, entity_id)
);

comment on table knowledge_bundle_entity is
    'Replaces Arango edge collection knowledge_bundle_entity_edge; a context-bundle child table, not a graph traversal edge.';

create table if not exists knowledge_bundle_relation (
    bundle_id uuid not null,
    relation_id uuid not null,
    library_id uuid not null,
    rank integer not null,
    score double precision not null,
    inclusion_reason text,
    created_at timestamptz not null,
    primary key (bundle_id, relation_id)
);

comment on table knowledge_bundle_relation is
    'Replaces Arango edge collection knowledge_bundle_relation_edge; a context-bundle child table, not a graph traversal edge.';

create table if not exists knowledge_bundle_evidence (
    bundle_id uuid not null,
    evidence_id uuid not null,
    library_id uuid not null,
    rank integer not null,
    score double precision not null,
    inclusion_reason text,
    created_at timestamptz not null,
    primary key (bundle_id, evidence_id)
);

comment on table knowledge_bundle_evidence is
    'Replaces Arango edge collection knowledge_bundle_evidence_edge; a context-bundle child table, not a graph traversal edge.';

create table if not exists knowledge_chunk_entity_mention (
    from_id uuid not null,
    to_id uuid not null,
    relation_type text not null default 'mentions',
    support bigint not null default 1,
    library_id uuid not null,
    rank integer,
    score double precision,
    inclusion_reason text,
    created_at timestamptz not null,
    updated_at timestamptz not null,
    primary key (from_id, to_id, relation_type)
);

comment on table knowledge_chunk_entity_mention is
    'Replaces Arango edge collection knowledge_chunk_mentions_entity_edge; retained as an indexed many-to-many edge because chunks may mention many entities and entities may be mentioned by many chunks.';

create table if not exists knowledge_evidence_entity_support (
    from_id uuid not null,
    to_id uuid not null,
    relation_type text not null default 'supports_entity',
    support bigint not null default 1,
    library_id uuid not null,
    rank integer,
    score double precision,
    inclusion_reason text,
    created_at timestamptz not null,
    updated_at timestamptz not null,
    primary key (from_id, to_id, relation_type)
);

comment on table knowledge_evidence_entity_support is
    'Replaces Arango edge collection knowledge_evidence_supports_entity_edge; retained as an indexed many-to-many provenance edge with rank/score.';

create table if not exists knowledge_evidence_relation_support (
    from_id uuid not null,
    to_id uuid not null,
    relation_type text not null default 'supports_relation',
    support bigint not null default 1,
    library_id uuid not null,
    rank integer,
    score double precision,
    inclusion_reason text,
    created_at timestamptz not null,
    updated_at timestamptz not null,
    primary key (from_id, to_id, relation_type)
);

comment on table knowledge_evidence_relation_support is
    'Replaces Arango edge collection knowledge_evidence_supports_relation_edge; retained as an indexed many-to-many provenance edge with rank/score.';

create table if not exists knowledge_vector_relation_manifest (
    library_id uuid not null,
    dim integer not null,
    vector_kind text not null,
    embedding_model_key text not null,
    relation_name text not null,
    is_default boolean not null default false,
    row_count bigint not null default 0,
    promoted boolean not null default false,
    created_at timestamptz not null default now(),
    primary key (library_id, dim, vector_kind, embedding_model_key)
);

comment on table knowledge_vector_relation_manifest is
    'Static W0 vector manifest. Per-dimension vector tables, LIST partitions, child relation routing, and HNSW/halfvec indexes are runtime DDL created by bootstrap/ingest/promotion because active dimensions are not known at migration time. Partition DDL must be batched <=250 partitions per transaction per the W0 ADR. Legacy Arango vector persistent indexes (knowledge_chunk_vector_* and knowledge_entity_vector_*) are runtime vector-table index contracts, not static baseline tables.';

comment on column runtime_graph_edge.rank is
    'W6 ingest-merge must populate this provenance rank for PostgreSQL context traversal parity with Arango graph edges.';
comment on column runtime_graph_edge.edge_score is
    'W6 ingest-merge must populate this score for context.rs edge_score answer-path reads.';
comment on column runtime_graph_edge.inclusion_reason is
    'W6 ingest-merge must populate this inclusion reason for context.rs inclusion_reason answer-path reads.';
comment on column runtime_graph_edge.support_edge_score is
    'W6 ingest-merge must populate this support score for context.rs support_edge_score answer-path reads.';
comment on column runtime_graph_evidence.rank is
    'W6 ingest-merge must populate this provenance rank for relation evidence lookup parity.';
comment on column runtime_graph_evidence.score is
    'W6 ingest-merge must populate this score for relation evidence lookup parity.';
comment on column runtime_graph_evidence.inclusion_reason is
    'W6 ingest-merge must populate this inclusion reason for context bundle evidence references.';
comment on column runtime_graph_evidence.support_edge_score is
    'W6 ingest-merge must populate this support score for context.rs support_edge_score answer-path reads.';
comment on column runtime_graph_evidence.support_edge_inclusion_reason is
    'W6 ingest-merge must populate this support inclusion reason for relation evidence lookup parity.';

