-- Per-chunk evidence hydration (WHERE chunk_id = $1) runs once per retrieved
-- chunk in the answer pipeline. Without this index it falls to a parallel seq
-- scan of the whole evidence table (~720 ms/chunk on a large corpus, ~20 s of
-- retrieval for a single answer); the partial index makes it a ~0.7 ms index
-- scan. Partial because most evidence rows target entities/relations and carry
-- a NULL chunk_id.
create index if not exists idx_runtime_graph_evidence_chunk_id ON public.runtime_graph_evidence USING btree (chunk_id) WHERE chunk_id IS NOT NULL;

create index if not exists idx_runtime_graph_evidence_library_target_document ON public.runtime_graph_evidence USING btree (library_id, target_kind, document_id, target_id) WHERE (document_id IS NOT NULL);

create index if not exists idx_runtime_graph_evidence_library_text_ready ON public.runtime_graph_evidence USING btree (library_id, created_at DESC, id DESC) WHERE (btrim(evidence_text) <> ''::text);

create index if not exists idx_runtime_graph_extraction_cache_lookup ON public.runtime_graph_extraction USING btree (library_id, extraction_version, provider_kind, model_name, prompt_hash, status, created_at DESC);

create index if not exists idx_runtime_graph_extraction_document_revision_status ON public.runtime_graph_extraction USING btree (document_id, ((raw_output_json #>> '{lifecycle,revision_id}'::text[])), status);

create index if not exists idx_runtime_graph_extraction_recovery_attempt_runtime_execution ON public.runtime_graph_extraction_recovery_attempt USING btree (runtime_execution_id, started_at);

create index if not exists idx_runtime_graph_extraction_runtime_execution_id ON public.runtime_graph_extraction USING btree (runtime_execution_id);

create index if not exists idx_runtime_graph_filtered_artifact_library_created_at ON public.runtime_graph_filtered_artifact USING btree (library_id, created_at DESC);

create index if not exists idx_runtime_graph_node_entity_aliases_trgm ON public.runtime_graph_node USING gin (lower((aliases_json)::text) public.gin_trgm_ops) WHERE (node_type <> 'document'::text);

-- Exact-match lookup index for entity labels. Indexes lower(label) only (NOT
-- the raw label too): a single ~1.6 KB label indexed twice overflows the btree
-- per-tuple limit (~2704 bytes) and aborts a whole-library restore. The
-- equality predicate is lower(n.label) = $; graph-node label writes are also
-- byte-clamped at extraction (runtime_graph_repository.rs) so a label can never
-- approach the limit.
create index if not exists idx_runtime_graph_node_entity_label_exact ON public.runtime_graph_node USING btree (library_id, projection_version, lower(label), support_count DESC, created_at, id) WHERE (node_type <> 'document'::text);

create index if not exists idx_runtime_graph_node_entity_label_trgm ON public.runtime_graph_node USING gin (lower(label) public.gin_trgm_ops) WHERE (node_type <> 'document'::text);

create index if not exists idx_runtime_graph_node_entity_summary_trgm ON public.runtime_graph_node USING gin (lower(COALESCE(summary, ''::text)) public.gin_trgm_ops) WHERE ((node_type <> 'document'::text) AND (summary IS NOT NULL) AND (btrim(summary) <> ''::text));

create index if not exists idx_runtime_graph_node_library_projection ON public.runtime_graph_node USING btree (library_id, projection_version, created_at);

create index if not exists idx_runtime_graph_node_library_projection_support_zero ON public.runtime_graph_node USING btree (library_id, projection_version) WHERE (support_count <= 0);

create index if not exists idx_runtime_graph_node_library_projection_type ON public.runtime_graph_node USING btree (library_id, projection_version, node_type);

create index if not exists idx_runtime_graph_node_projection_entity_support ON public.runtime_graph_node USING btree (library_id, projection_version, support_count DESC, label, created_at, id) WHERE (node_type <> 'document'::text);

create index if not exists idx_runtime_graph_node_projection_type_label_created ON public.runtime_graph_node USING btree (library_id, projection_version, node_type, label, created_at);

create unique index if not exists idx_runtime_graph_node_unique_document ON public.runtime_graph_node USING btree (library_id, document_id, projection_version) WHERE (node_type = 'document'::text);

create index if not exists idx_runtime_policy_decision_execution ON public.runtime_policy_decision USING btree (runtime_execution_id, created_at);

create index if not exists idx_runtime_provider_validation_log_library_created_at ON public.runtime_provider_validation_log USING btree (library_id, created_at DESC);

create index if not exists idx_runtime_provider_validation_log_provider_created_at ON public.runtime_provider_validation_log USING btree (provider_kind, model_name, capability, created_at DESC);

create index if not exists idx_runtime_stage_record_execution ON public.runtime_stage_record USING btree (runtime_execution_id, stage_ordinal, attempt_no);

create index if not exists idx_webhook_delivery_event ON public.webhook_delivery_attempt USING btree (event_type, event_id);

create index if not exists idx_webhook_delivery_job ON public.webhook_delivery_attempt USING btree (job_id) WHERE (job_id IS NOT NULL);

create index if not exists idx_webhook_delivery_subscription_state ON public.webhook_delivery_attempt USING btree (subscription_id, delivery_state, next_attempt_at);

create index if not exists idx_webhook_subscription_library_active ON public.webhook_subscription USING btree (library_id, active) WHERE (active AND (library_id IS NOT NULL));

create index if not exists idx_webhook_subscription_workspace_active ON public.webhook_subscription USING btree (workspace_id, active) WHERE active;

create index if not exists maintenance_job_run_dead_letter_idx ON public.maintenance_job_run USING btree (class, updated_at) WHERE (state = 'dead_letter'::public.maintenance_run_state);

create index if not exists maintenance_job_run_due_idx ON public.maintenance_job_run USING btree (class, next_due_at) WHERE (state = 'pending'::public.maintenance_run_state);

create index if not exists maintenance_job_run_heartbeat_idx ON public.maintenance_job_run USING btree (heartbeat_at) WHERE (state = 'leased'::public.maintenance_run_state);

create unique index if not exists maintenance_job_run_scope_key ON public.maintenance_job_run USING btree (class, scope_kind, COALESCE(scope_id, '00000000-0000-0000-0000-000000000000'::uuid));

create index if not exists runtime_execution_parent_idx ON public.runtime_execution USING btree (parent_execution_id) WHERE (parent_execution_id IS NOT NULL);

create index if not exists runtime_graph_community_lib_ver_idx ON public.runtime_graph_community USING btree (library_id, projection_version);

create index if not exists runtime_graph_community_members_idx ON public.runtime_graph_community USING gin (member_node_ids);

