    modality_kind   = excluded.modality_kind,
    lifecycle_state = excluded.lifecycle_state;

-- Bootstrap instance-scoped presets so each Ollama model appears in the
-- UI dropdown out of the box. Idempotent via NOT EXISTS guard.
insert into ai_model_preset (id, model_catalog_id, preset_name, scope_kind)
select uuidv7(), m.id, 'Ollama ' || m.model_name, 'instance'::ai_scope_kind
  from ai_model_catalog m
  join ai_provider_catalog p on p.id = m.provider_catalog_id
 where p.provider_kind = 'ollama'
   and not exists (
       select 1 from ai_model_preset mp
       where mp.model_catalog_id = m.id and mp.preset_name = 'Ollama ' || m.model_name
   )
on conflict do nothing;

-- 0005_v0_4_2_provider_catalog_normalization.sql: multi-provider profiles, models, presets, prices.

-- 3. Multi-provider AI catalog seed + currency normalization.

-- ---------------------------------------------------------------------
-- Provider catalog profiles: canonical provider behavior metadata for
-- credential validation, base URL handling, model discovery, runtime
-- paths, and bootstrap presets. Keep provider policy in data so runtime
-- code does not need provider-name branches for router-compatible APIs.
--
-- Provider ids 0105..0107 and model ids 0288..0290 are reserved here for
-- OpenAI-compatible router providers.
-- ---------------------------------------------------------------------

with provider_profiles (
    id,
    provider_kind,
    display_name,
    api_style,
    lifecycle_state,
    default_base_url,
    capability_flags_json
) as (
    values
    (
        '00000000-0000-0000-0000-000000000101'::uuid,
        'openai',
        'OpenAI',
        'openai_compatible'::ai_provider_api_style,
        'active'::ai_provider_lifecycle_state,
        'https://api.openai.com/v1',
        $json${
            "runtime": {"kind":"openai_compatible","authScheme":"bearer","tokenLimitParameter":"max_completion_tokens","structuredOutput":"json_schema","chatPath":"/chat/completions","embeddingsPath":"/embeddings","modelsPath":"/models"},
            "credentials": {"apiKeyRequired":true,"baseUrlRequired":false,"baseUrlMode":"fixed","validationMode":"chat_round_trip"},
            "baseUrl": {"allowOverride":false,"requireHttps":true,"allowPrivateNetwork":false,"trimSuffixes":[]},
