insert into ai_model_catalog (
    id,
    provider_catalog_id,
    model_name,
    capability_kind,
    modality_kind,
    lifecycle_state,
    metadata_json
)
select
    router_models.id,
    ai_provider_catalog.id,
    router_models.model_name,
    router_models.capability_kind,
    router_models.modality_kind,
    router_models.lifecycle_state,
    router_models.metadata_json
from router_models
join ai_provider_catalog
  on ai_provider_catalog.provider_kind = router_models.provider_kind
on conflict (provider_catalog_id, model_name, capability_kind) do update set
    metadata_json   = excluded.metadata_json,
    modality_kind   = excluded.modality_kind,
    lifecycle_state = excluded.lifecycle_state;


with provider_extract_text_presets as (
    select
        provider.id,
        jsonb_agg(
            jsonb_build_object(
                'purpose',
                'extract_text',
                'modelName',
                graph_preset ->> 'modelName'
            )
        ) as additions
    from ai_provider_catalog provider
    cross join lateral jsonb_array_elements(
        case
            when jsonb_typeof(provider.capability_flags_json -> 'bootstrapPresets') = 'array'
                then provider.capability_flags_json -> 'bootstrapPresets'
            else '[]'::jsonb
        end
    ) graph_preset
    where graph_preset ->> 'purpose' = 'extract_graph'
      and not exists (
          select 1
          from jsonb_array_elements(
              case
                  when jsonb_typeof(provider.capability_flags_json -> 'bootstrapPresets') = 'array'
                      then provider.capability_flags_json -> 'bootstrapPresets'
                  else '[]'::jsonb
              end
          ) existing_preset
          where existing_preset ->> 'purpose' = 'extract_text'
      )
    group by provider.id
)
update ai_provider_catalog provider
set capability_flags_json = jsonb_set(
        provider.capability_flags_json,
        '{bootstrapPresets}',
        provider.capability_flags_json -> 'bootstrapPresets' || provider_extract_text_presets.additions,
        true
    )
from provider_extract_text_presets
where provider.id = provider_extract_text_presets.id;

with provider_query_retrieve_presets as (
    select
        provider.id,
        jsonb_agg(
            jsonb_build_object(
                'purpose',
                'query_retrieve',
                'modelName',
                embed_preset ->> 'modelName'
            )
        ) as additions
    from ai_provider_catalog provider
    cross join lateral jsonb_array_elements(
        case
            when jsonb_typeof(provider.capability_flags_json -> 'bootstrapPresets') = 'array'
                then provider.capability_flags_json -> 'bootstrapPresets'
            else '[]'::jsonb
        end
    ) embed_preset
    where embed_preset ->> 'purpose' = 'embed_chunk'
      and not exists (
          select 1
          from jsonb_array_elements(
              case
                  when jsonb_typeof(provider.capability_flags_json -> 'bootstrapPresets') = 'array'
                      then provider.capability_flags_json -> 'bootstrapPresets'
                  else '[]'::jsonb
              end
          ) existing_preset
          where existing_preset ->> 'purpose' = 'query_retrieve'
      )
    group by provider.id
)
update ai_provider_catalog provider
set capability_flags_json = jsonb_set(
        provider.capability_flags_json,
        '{bootstrapPresets}',
        provider.capability_flags_json -> 'bootstrapPresets' || provider_query_retrieve_presets.additions,
        true
    )
from provider_query_retrieve_presets
where provider.id = provider_query_retrieve_presets.id;

update ai_model_catalog
set metadata_json = jsonb_set(
        metadata_json,
        '{defaultRoles}',
        case
            when jsonb_typeof(metadata_json -> 'defaultRoles') = 'array'
                then metadata_json -> 'defaultRoles' || '["extract_text"]'::jsonb
            else '["extract_text"]'::jsonb
        end,
        true
    )
where capability_kind = 'chat'
  and exists (
      select 1
      from jsonb_array_elements(
          case
              when jsonb_typeof(metadata_json -> 'defaultRoles') = 'array'
                  then metadata_json -> 'defaultRoles'
              else '[]'::jsonb
          end
      ) default_role
      where default_role = '"extract_graph"'::jsonb
  )
  and not exists (
      select 1
      from jsonb_array_elements(
          case
              when jsonb_typeof(metadata_json -> 'defaultRoles') = 'array'
                  then metadata_json -> 'defaultRoles'
              else '[]'::jsonb
          end
      ) default_role
      where default_role = '"extract_text"'::jsonb
  );

update ai_model_catalog
set metadata_json = jsonb_set(
        metadata_json,
        '{defaultRoles}',
        case
            when jsonb_typeof(metadata_json -> 'defaultRoles') = 'array'
                then metadata_json -> 'defaultRoles' || '["query_retrieve"]'::jsonb
            else '["query_retrieve"]'::jsonb
        end,
        true
    )
where capability_kind = 'embedding'
  and not exists (
      select 1
      from jsonb_array_elements(
          case
              when jsonb_typeof(metadata_json -> 'defaultRoles') = 'array'
                  then metadata_json -> 'defaultRoles'
              else '[]'::jsonb
          end
      ) default_role
      where default_role = '"query_retrieve"'::jsonb
  );

with provider_query_compile_models as (
    select model.id
    from ai_provider_catalog provider
    join lateral jsonb_array_elements(
        case
            when jsonb_typeof(provider.capability_flags_json -> 'bootstrapPresets') = 'array'
                then provider.capability_flags_json -> 'bootstrapPresets'
            else '[]'::jsonb
        end
    ) preset on true
    join ai_model_catalog model
      on model.provider_catalog_id = provider.id
     and model.model_name = preset ->> 'modelName'
    where preset ->> 'purpose' = 'query_compile'
)
update ai_model_catalog model
set metadata_json = jsonb_set(
        model.metadata_json,
        '{defaultRoles}',
        case
            when jsonb_typeof(model.metadata_json -> 'defaultRoles') = 'array'
                then model.metadata_json -> 'defaultRoles' || '["query_compile"]'::jsonb
            else '["query_compile"]'::jsonb
        end,
        true
    )
from provider_query_compile_models
where model.id = provider_query_compile_models.id
  and not exists (
      select 1
      from jsonb_array_elements(
          case
              when jsonb_typeof(model.metadata_json -> 'defaultRoles') = 'array'
                  then model.metadata_json -> 'defaultRoles'
              else '[]'::jsonb
          end
      ) default_role
      where default_role = '"query_compile"'::jsonb
  );

