-- ==============================================================
-- Cleanup: drop catalog rows that don't belong in text/embedding/vision
-- pipeline (audio/image/legacy/agent/etc). Idempotent — safe to re-run.
-- ==============================================================
-- Delete catalog rows + presets + prices for models that don't belong in the
-- text/embedding/vision pipeline (audio/image/video/legacy/agent/etc).
-- Pattern matches the exclusions baked into classify() in
-- scripts/all-providers-seed-gen.py.

WITH bad AS (
    SELECT m.id
    FROM ai_model_catalog m
    WHERE m.model_name ~* (
        '(^|/|-)whisper|(^|-)tts(-|$|\d)|/tts|transcribe|audio-preview|realtime|'
        || '(^|-|/)audio(-|$)|dall-e|dalle|gpt-image|/image-1|/image-2|image-3|'
        || 'image-edit|image-gen|stable-diffusion|/flux|^flux-|midjourney|'
        || 'playground-|video-|^sora|/sora|runway-|veo-|kling-|'
        || '(^|-|/)davinci|babbage|(^|-|/)ada-|curie|(^|-|/)gpt-3-|'
        || 'text-completion|text-davinci|computer-use|search-api|deep-research|'
        || 'browser-use|operator|moderation|omni-moderation|safety-|'
        || 'rerank|-reranker'
    )
)
DELETE FROM ai_model_preset WHERE model_catalog_id IN (SELECT id FROM bad);

WITH bad AS (
    SELECT m.id
    FROM ai_model_catalog m
    WHERE m.model_name ~* (
        '(^|/|-)whisper|(^|-)tts(-|$|\d)|/tts|transcribe|audio-preview|realtime|'
        || '(^|-|/)audio(-|$)|dall-e|dalle|gpt-image|/image-1|/image-2|image-3|'
        || 'image-edit|image-gen|stable-diffusion|/flux|^flux-|midjourney|'
        || 'playground-|video-|^sora|/sora|runway-|veo-|kling-|'
        || '(^|-|/)davinci|babbage|(^|-|/)ada-|curie|(^|-|/)gpt-3-|'
        || 'text-completion|text-davinci|computer-use|search-api|deep-research|'
        || 'browser-use|operator|moderation|omni-moderation|safety-|'
        || 'rerank|-reranker'
    )
)
DELETE FROM ai_price_catalog WHERE model_catalog_id IN (SELECT id FROM bad);

DELETE FROM ai_model_catalog
WHERE model_name ~* (
    '(^|/|-)whisper|(^|-)tts(-|$|\d)|/tts|transcribe|audio-preview|realtime|'
    || '(^|-|/)audio(-|$)|dall-e|dalle|gpt-image|/image-1|/image-2|image-3|'
    || 'image-edit|image-gen|stable-diffusion|/flux|^flux-|midjourney|'
    || 'playground-|video-|^sora|/sora|runway-|veo-|kling-|'
    || '(^|-|/)davinci|babbage|(^|-|/)ada-|curie|(^|-|/)gpt-3-|'
    || 'text-completion|text-davinci|computer-use|search-api|deep-research|'
    || 'browser-use|operator|moderation|omni-moderation|safety-|'
    || 'rerank|-reranker'
);

-- ==============================================================
-- Cleanup: drop tts-* models (POSIX regex \d quirk)
-- ==============================================================
WITH bad AS (SELECT id FROM ai_model_catalog WHERE model_name ~* '(^|-)tts(-|[0-9]|$)')
DELETE FROM ai_model_preset WHERE model_catalog_id IN (SELECT id FROM bad);
DELETE FROM ai_price_catalog WHERE model_catalog_id IN (SELECT id FROM ai_model_catalog WHERE model_name ~* '(^|-)tts(-|[0-9]|$)');
DELETE FROM ai_model_catalog WHERE model_name ~* '(^|-)tts(-|[0-9]|$)';

