INSERT INTO ai_model_preset (
    scope_kind, workspace_id, library_id,
    model_catalog_id, preset_name,
    temperature, top_p, extra_parameters_json
)
SELECT
    'instance'::ai_scope_kind, NULL, NULL,
    m.id, p.preset_name, p.temperature, p.top_p, '{}'::jsonb
FROM ai_model_catalog m
JOIN (VALUES
        ('chat-latest', 'Openai Query Answer · chat-latest', 0.3, 0.9),
        ('chat-latest', 'Openai Extract Graph · chat-latest', 0.3, 0.9),
        ('chat-latest', 'Openai Query Compile · chat-latest', 0.3, 0.9),
        ('gpt-3.5-turbo', 'Openai Query Answer · gpt-3.5-turbo', 0.3, 0.9),
        ('gpt-3.5-turbo', 'Openai Extract Graph · gpt-3.5-turbo', 0.3, 0.9),
        ('gpt-3.5-turbo', 'Openai Query Compile · gpt-3.5-turbo', 0.3, 0.9),
