-- ──────────────────────────────────────────────────────────────────────
-- gptunnel currency normalization (canonical USD-only catalog)
--
-- The gptunnel price block above was seeded in RUB because the live
-- gptunnel /v1/models feed publishes RUB. The billing UI renders
-- `unit_price` with a `$` glyph regardless of `currency_code`, so a
-- 4-chunk document showed ~$0.44 instead of the real ~$0.0046 — an
-- 800× artifact of the RUB→display-USD mismatch.
--
-- The catalog must hold one currency. Convert every RUB row to USD at
-- a fixed FX (95 RUB/USD ≈ 2026-Q2 spot rate; the seed script will
-- refine this when re-baselined). Idempotent: rows already in USD are
-- untouched.
-- ──────────────────────────────────────────────────────────────────────
UPDATE ai_price_catalog
SET unit_price = ROUND(unit_price / 95, 8),
    currency_code = 'USD'
WHERE currency_code = 'RUB';

-- ──────────────────────────────────────────────────────────────────────
-- routerai currency normalization (canonical USD-only catalog)
--
-- The routerai live-pricing seed above pulls `pricing.{prompt,completion}`
-- from /v1/models and multiplies by 1e6 to derive per-million rates.
-- The router-ai feed publishes those values in RUB, not USD, so the
-- generated rows were 96.585× the real USD price (FX measured against
-- openai/o1-pro: routerai $57951.11 ÷ openrouter $600 = 96.585, the
-- 2026-Q2 RUB/USD spot rate). Convert to USD here.
--
-- Idempotent: gated on the existence of at least one routerai row priced
-- above $1000/M, which only happens with un-converted RUB values. The
-- highest legitimate USD price in the catalog is $600/M (openai/o1-pro),
-- so re-applying this UPDATE after conversion is a no-op.
-- ──────────────────────────────────────────────────────────────────────
DO $routerai_fx$
BEGIN
    IF EXISTS (
        SELECT 1
        FROM ai_price_catalog p
        JOIN ai_model_catalog m ON m.id = p.model_catalog_id
        JOIN ai_provider_catalog pc ON pc.id = m.provider_catalog_id
        WHERE pc.provider_kind = 'routerai' AND p.unit_price > 1000
    ) THEN
        UPDATE ai_price_catalog p
        SET unit_price = ROUND(p.unit_price / 96.585, 8)
        FROM ai_model_catalog m
        JOIN ai_provider_catalog pc ON pc.id = m.provider_catalog_id
        WHERE p.model_catalog_id = m.id
          AND pc.provider_kind = 'routerai'
          AND p.billing_unit IN ('per_1m_input_tokens'::billing_unit, 'per_1m_output_tokens'::billing_unit);
    END IF;
END
$routerai_fx$;

-- 0007_agent_binding_canonical.sql: reference model-role normalization only; binding backfills are user/deployment data.

-- Recompute defaultRoles for every text-chat model so the canonical
-- chat purposes (extract_text, extract_graph, query_compile,
-- query_answer, agent) become selectable in the admin UI for chat
-- models that were seeded before purposes expanded.
update ai_model_catalog
set metadata_json = jsonb_set(
    metadata_json,
    '{defaultRoles}',
    to_jsonb(array['extract_text','extract_graph','query_compile','query_answer','agent']),
    true
)
where capability_kind = 'chat'
  and modality_kind = 'text';

-- Recompute defaultRoles for multimodal chat models (chat + vision).
update ai_model_catalog
set metadata_json = jsonb_set(
    metadata_json,
    '{defaultRoles}',
    to_jsonb(array['extract_text','extract_graph','query_compile','query_answer','vision','agent']),
    true
)
where capability_kind = 'chat'
  and modality_kind = 'multimodal';

-- 0010_ingest_queue_rank.sql: OpenRouter 3072-dimension embedding catalog/presets.

-- Canonical OpenRouter 3072-dimension embedding baseline.
--
-- OpenRouter exposes more embedding models, but most return dimensions that do
-- not match the current vector index. Seed only models that have been verified
-- to produce 3072-dimensional vectors through the IronRAG request shape.

with openrouter_embedding_models (
    id,
    model_name
) as (
    values
        (
            'c4ab7bf4-9d0c-5270-9f8b-2c5604d4b744'::uuid,
            'openai/text-embedding-3-large'
        ),
        (
            '617154cb-2ef1-5f77-ae2c-487adcd4fac8'::uuid,
            'qwen/qwen3-embedding-8b'
        )
)
insert into ai_model_catalog (
    id,
    provider_catalog_id,
    model_name,
    capability_kind,
    modality_kind,
    lifecycle_state,
    metadata_json
)
select
    openrouter_embedding_models.id,
    provider.id,
    openrouter_embedding_models.model_name,
    'embedding'::ai_model_capability_kind,
    'text'::ai_model_modality_kind,
    'active'::ai_model_lifecycle_state,
    '{"defaultRoles":["embed_chunk","query_retrieve"],"seedSource":"provider_catalog"}'::jsonb
from ai_provider_catalog provider
join openrouter_embedding_models on true
where provider.provider_kind = 'openrouter'
on conflict (provider_catalog_id, model_name, capability_kind) do update set
    modality_kind = excluded.modality_kind,
    lifecycle_state = excluded.lifecycle_state,
    metadata_json = excluded.metadata_json;

with openrouter_embedding_presets (
    model_name,
    preset_name,
    extra_parameters_json
) as (
    values
        (
            'openai/text-embedding-3-large',
            'OpenRouter Embed Chunk · openai/text-embedding-3-large',
            '{}'::jsonb
        ),
        (
