    scope_kind,
    workspace_id,
    library_id,
    model_catalog_id,
    preset_name,
    temperature,
    top_p,
    extra_parameters_json
)
select
    'instance'::ai_scope_kind,
    null,
    null,
    model.id,
    openrouter_embedding_presets.preset_name,
    null,
    null,
    openrouter_embedding_presets.extra_parameters_json
from ai_model_catalog model
join ai_provider_catalog provider on provider.id = model.provider_catalog_id
join openrouter_embedding_presets
  on openrouter_embedding_presets.model_name = model.model_name
where provider.provider_kind = 'openrouter'
  and model.capability_kind = 'embedding'
on conflict do nothing;


-- =====================================================================
-- 0.5.0 baseline addendum: system-role RBAC (folded pre-release).
-- Adds iam_user.role; idempotent so it composes cleanly into the baseline.
-- =====================================================================
-- 1. System-role enum.
do $$
begin
    if not exists (
        select 1
        from pg_type
        where typname = 'iam_system_role'
          and typnamespace = 'public'::regnamespace
    ) then
        create type public.iam_system_role as enum (
            'viewer',
            'operator',
            'admin'
        );
    end if;
end
$$;

-- 2. Role column on iam_user, defaulting to the least-privileged tier.
alter table public.iam_user
    add column if not exists role public.iam_system_role not null default 'viewer';

-- 3. Promote the bootstrap administrator(s) to 'admin'.
--    Recompute-from-canonical: the bootstrap admin is the principal that holds
--    the system-scoped iam_admin grant (see iam_repository::claim_bootstrap_user
--    and setup_bootstrap_admin). Re-running this UPDATE is a no-op once the role
--    is already 'admin'.
update public.iam_user as users
set role = 'admin'
where role <> 'admin'
  and exists (
      select 1
      from public.iam_grant as grants
      where grants.principal_id = users.principal_id
        and grants.resource_kind = 'system'
        and grants.permission_kind = 'iam_admin'
        and (grants.expires_at is null or grants.expires_at > now())
  );


