catalog_seed as (
    select
        (
            substr(md5(concat_ws(':', 'ironrag', model_seed.provider_kind, 'model', model_seed.model_name, 'chat')), 1, 8) || '-' ||
            substr(md5(concat_ws(':', 'ironrag', model_seed.provider_kind, 'model', model_seed.model_name, 'chat')), 9, 4) || '-' ||
            substr(md5(concat_ws(':', 'ironrag', model_seed.provider_kind, 'model', model_seed.model_name, 'chat')), 13, 4) || '-' ||
            substr(md5(concat_ws(':', 'ironrag', model_seed.provider_kind, 'model', model_seed.model_name, 'chat')), 17, 4) || '-' ||
            substr(md5(concat_ws(':', 'ironrag', model_seed.provider_kind, 'model', model_seed.model_name, 'chat')), 21, 12)
        )::uuid as id,
        provider.id as provider_catalog_id,
        model_seed.provider_kind,
        model_seed.model_name,
        model_seed.modality_kind,
        model_seed.context_window,
        jsonb_build_object(
            'defaultRoles', to_jsonb(model_seed.default_roles),
            'seedSource', 'provider_catalog'
        ) as metadata_json
    from model_seed
    join ai_provider_catalog provider on provider.provider_kind = model_seed.provider_kind
)
insert into ai_model_catalog (
    id,
    provider_catalog_id,
    model_name,
    capability_kind,
    modality_kind,
    context_window,
    max_output_tokens,
    lifecycle_state,
    metadata_json
)
select
    id,
    provider_catalog_id,
    model_name,
    'chat'::ai_model_capability_kind,
    modality_kind,
    context_window,
    null,
    'active'::ai_model_lifecycle_state,
    metadata_json
from catalog_seed
on conflict (provider_catalog_id, model_name, capability_kind) do update set
    modality_kind = excluded.modality_kind,
    context_window = excluded.context_window,
    lifecycle_state = 'active'::ai_model_lifecycle_state,
    metadata_json = excluded.metadata_json;

with role_titles(role_name, role_title) as (
    values
        ('query_answer', 'Query Answer'),
        ('extract_graph', 'Extract Graph'),
        ('query_compile', 'Query Compile'),
        ('vision', 'Vision')
),
eligible_models as (
    select
        provider.display_name as provider_display_name,
        model.id as model_catalog_id,
        model.model_name,
        jsonb_array_elements_text(model.metadata_json -> 'defaultRoles') as role_name
    from ai_model_catalog model
    join ai_provider_catalog provider on provider.id = model.provider_catalog_id
    where provider.provider_kind in ('qwen', 'openrouter', 'routerai')
      and model.lifecycle_state = 'active'
      and (
          (provider.provider_kind = 'qwen' and model.model_name in (
              'qwen3.7-max',
              'qwen3.7-max-2026-05-20',
              'qwen3.7-max-preview',
              'qwen3.7-max-2026-05-17',
              'qwen3.7-plus',
              'qwen3.7-plus-2026-05-26',
              'glm-5.1',
              'kimi-k2.6',
              'MiniMax-M2.5',
              'mimo-v2.5-pro',
              'deepseek-v4-pro',
              'deepseek-v4-flash'
          ))
          or (provider.provider_kind in ('openrouter', 'routerai') and model.model_name in (
              'qwen/qwen3.7-max',
              'qwen/qwen3.7-plus',
              'minimax/minimax-m2.5',
              'moonshotai/kimi-k2.6',
              'z-ai/glm-5.1'
          ))
      )
)
insert into ai_model_preset (
    scope_kind,
    workspace_id,
    library_id,
    model_catalog_id,
    preset_name,
    temperature,
    top_p,
    extra_parameters_json
)
select
    'instance'::ai_scope_kind,
    null,
    null,
    eligible.model_catalog_id,
    eligible.provider_display_name || ' ' || role_titles.role_title || ' · ' || eligible.model_name,
    0.3,
    0.9,
    '{}'::jsonb
from eligible_models eligible
join role_titles on role_titles.role_name = eligible.role_name
on conflict do nothing;

