    select
        (
            substr(md5(concat_ws(':', 'ironrag', price_seed.provider_kind, 'price', price_seed.model_name, price_seed.billing_unit::text)), 1, 8) || '-' ||
            substr(md5(concat_ws(':', 'ironrag', price_seed.provider_kind, 'price', price_seed.model_name, price_seed.billing_unit::text)), 9, 4) || '-' ||
            substr(md5(concat_ws(':', 'ironrag', price_seed.provider_kind, 'price', price_seed.model_name, price_seed.billing_unit::text)), 13, 4) || '-' ||
            substr(md5(concat_ws(':', 'ironrag', price_seed.provider_kind, 'price', price_seed.model_name, price_seed.billing_unit::text)), 17, 4) || '-' ||
            substr(md5(concat_ws(':', 'ironrag', price_seed.provider_kind, 'price', price_seed.model_name, price_seed.billing_unit::text)), 21, 12)
        )::uuid as id,
        model.id as model_catalog_id,
        price_seed.billing_unit,
        price_seed.unit_price,
        price_seed.currency_code
    from price_seed
    join ai_provider_catalog provider on provider.provider_kind = price_seed.provider_kind
    join ai_model_catalog model
      on model.provider_catalog_id = provider.id
     and model.model_name = price_seed.model_name
     and model.capability_kind = 'chat'::ai_model_capability_kind
)
