    id,
    model_catalog_id,
    billing_unit,
    'default',
    null,
    null,
    unit_price,
    currency_code,
    timestamptz '2026-06-04 00:00:00+00',
    null,
    'system'::ai_price_catalog_scope,
    null
from resolved_price_seed
on conflict do nothing;

update ai_provider_catalog provider
set capability_flags_json = jsonb_set(
        provider.capability_flags_json,
        '{bootstrapPresets}',
        (
            select jsonb_agg(
                case
                    when item ->> 'purpose' in ('extract_text', 'extract_graph', 'query_compile', 'query_answer')
                        then jsonb_set(item, '{modelName}', to_jsonb('qwen3.7-plus'::text), true)
                    else item
                end
                order by ordinality
            )
            from jsonb_array_elements(provider.capability_flags_json -> 'bootstrapPresets')
                 with ordinality as presets(item, ordinality)
        ),
        true
    )
where provider.provider_kind = 'qwen'
  and jsonb_typeof(provider.capability_flags_json -> 'bootstrapPresets') = 'array';
